if post1_self_.valid() && post2_self_.valid()
        && (match r1 {
            Some(r1m) => {
                &&& r1m.abstractable()
                &&& r1m is Message
                &&& r1m.arrow_Message_dst()@ == dst@
                &&& SingleDelivery::send_single_message(pre_self_@, post1_self_@, m@, dst@, Some(r1m@), AbstractParameters::static_params())
                &&& r1m.is_marshalable()
            },
            None => SingleDelivery::send_single_message(pre_self_@, post1_self_@, m@, dst@, None, AbstractParameters::static_params()),
        })
        && (match r2 {
            Some(r2m) => {
                &&& r2m.abstractable()
                &&& r2m is Message
                &&& r2m.arrow_Message_dst()@ == dst@
                &&& SingleDelivery::send_single_message(pre_self_@, post2_self_@, m@, dst@, Some(r2m@), AbstractParameters::static_params())
                &&& r2m.is_marshalable()
            },
            None => SingleDelivery::send_single_message(pre_self_@, post2_self_@, m@, dst@, None, AbstractParameters::static_params()),
        })
    {
        assert((r1 is Some) == (r2 is Some));
        assert(post1_self_@ =~= post2_self_@);
        assert(post1_self_.receive_state@ == post2_self_.receive_state@);
        assert(post1_self_.send_state@ == post2_self_.send_state@);
    }
